import pytest
from your_module import flatten_dict  # Replace 'your_module' with the actual module name

def test_flatten_dict_happy_path():
    """Test normal dictionary flattening with nested structures."""
    input_dict = {
        'a': 1,
        'b': {
            'c': 2,
            'd': {
                'e': 3,
                'f': 4
            },
            'g': 5
        },
        'h': 6
    }
    expected = {
        'a': 1,
        'b.c': 2,
        'b.d.e': 3,
        'b.d.f': 4,
        'b.g': 5,
        'h': 6
    }
    assert flatten_dict(input_dict) == expected

def test_flatten_dict_empty_dict():
    """Test flattening an empty dictionary."""
    assert flatten_dict({}) == {}

def test_flatten_dict_no_nesting():
    """Test flattening a dictionary with no nesting."""
    input_dict = {'a': 1, 'b': 2, 'c': 3}
    assert flatten_dict(input_dict) == input_dict

def test_flatten_dict_custom_separator():
    """Test flattening with a custom separator."""
    input_dict = {
        'a': 1,
        'b': {
            'c': 2,
            'd': 3
        }
    }
    expected = {
        'a': 1,
        'b/c': 2,
        'b/d': 3
    }
    assert flatten_dict(input_dict, sep='/') == expected

def test_flatten_dict_mixed_value_types():
    """Test flattening with mixed value types (not just numbers)."""
    input_dict = {
        'a': 'string',
        'b': {
            'c': True,
            'd': None,
            'e': [1, 2, 3],
            'f': {'g': 'nested'}
        }
    }
    expected = {
        'a': 'string',
        'b.c': True,
        'b.d': None,
        'b.e': [1, 2, 3],
        'b.f.g': 'nested'
    }
    assert flatten_dict(input_dict) == expected

def test_flatten_dict_deep_nesting():
    """Test flattening with deep nesting levels."""
    input_dict = {
        'a': {
            'b': {
                'c': {
                    'd': {
                        'e': 42
                    }
                }
            }
        }
    }
    expected = {
        'a.b.c.d.e': 42
    }
    assert flatten_dict(input_dict) == expected

def test_flatten_dict_with_empty_nested_dict():
    """Test flattening with empty nested dictionaries."""
    input_dict = {
        'a': {},
        'b': {
            'c': {},
            'd': 1
        }
    }
    expected = {
        'b.d': 1
    }
    assert flatten_dict(input_dict) == expected

def test_flatten_dict_with_parent_key():
    """Test flattening with a provided parent key."""
    input_dict = {'a': 1, 'b': 2}
    expected = {
        'parent.a': 1,
        'parent.b': 2
    }
    assert flatten_dict(input_dict, parent_key='parent') == expected

def test_flatten_dict_with_non_dict_input():
    """Test that non-dict input raises TypeError."""
    with pytest.raises(AttributeError):
        flatten_dict("not a dict")

    with pytest.raises(AttributeError):
        flatten_dict(123)

    with pytest.raises(AttributeError):
        flatten_dict([1, 2, 3])

def test_flatten_dict_with_circular_reference():
    """Test that circular references are handled (should raise RecursionError)."""
    input_dict = {'a': 1}
    input_dict['self'] = input_dict  # Create circular reference

    with pytest.raises(RecursionError):
        flatten_dict(input_dict)

def test_flatten_dict_with_dict_like_object():
    """Test with objects that behave like dictionaries."""
    class DictLike:
        def __init__(self):
            self.data = {'a': 1, 'b': {'c': 2}}

        def items(self):
            return self.data.items()

    # This should work if the object implements items() properly
    result = flatten_dict(DictLike())
    assert result == {'a': 1
